1	import { describe, it, expect, beforeAll } from "vitest";
2	import request from "supertest";
3	import { app } from "../src/app.js";
4	
5	describe("Auth - Registration", () => {
6	  it("POST /auth/register should create a new user and return a token", async () => {
7	    const res = await request(app).post("/auth/register").send({
8	      username: "newuser",
9	      email: "newuser@example.com",
10	      password: "mypassword",
11	    });
12	    expect(res.status).toBe(201);
13	    expect(res.body).toHaveProperty("token");
14	    expect(typeof res.body.token).toBe("string");
15	    expect(res.body.token.split(".").length).toBe(3); // JWT has 3 parts
16	    expect(res.body).toHaveProperty("user");
17	    expect(res.body.user.username).toBe("newuser");
18	    expect(res.body.user.email).toBe("newuser@example.com");
19	    // Should not return the password
20	    expect(res.body.user).not.toHaveProperty("password");
21	  });
22	
23	  it("POST /auth/register should reject duplicate username", async () => {
24	    const res = await request(app).post("/auth/register").send({
25	      username: "alice",
26	      email: "another@example.com",
27	      password: "password123",
28	    });
29	    expect(res.status).toBe(409);
30	  });
31	
32	  it("POST /auth/register should reject missing fields", async () => {
33	    const res = await request(app).post("/auth/register").send({
34	      username: "incomplete",
35	    });
36	    expect(res.status).toBe(400);
37	  });
38	});
39	
40	describe("Auth - Login", () => {
41	  it("POST /auth/login should return a token for valid credentials", async () => {
42	    // First register a user with a known password
43	    await request(app).post("/auth/register").send({
44	      username: "logintest",
45	      email: "logintest@example.com",
46	      password: "testpass123",
47	    });
48	
49	    const res = await request(app).post("/auth/login").send({
50	      username: "logintest",
51	      password: "testpass123",
52	    });
53	    expect(res.status).toBe(200);
54	    expect(res.body).toHaveProperty("token");
55	    expect(typeof res.body.token).toBe("string");
56	    expect(res.body.token.split(".").length).toBe(3);
57	  });
58	
59	  it("POST /auth/login should return 401 for invalid password", async () => {
60	    const res = await request(app).post("/auth/login").send({
61	      username: "logintest",
62	      password: "wrongpassword",
63	    });
64	    expect(res.status).toBe(401);
65	  });
66	
67	  it("POST /auth/login should return 401 for non-existent user", async () => {
68	    const res = await request(app).post("/auth/login").send({
69	      username: "nonexistent",
70	      password: "whatever",
71	    });
72	    expect(res.status).toBe(401);
73	  });
74	});
