76	describe("Auth - Protected Routes", () => {
77	  let token: string;
78	
79	  beforeAll(async () => {
80	    // Register and get a token
81	    const res = await request(app).post("/auth/register").send({
82	      username: "authuser",
83	      email: "authuser@example.com",
84	      password: "authpass",
85	    });
86	    token = res.body.token;
87	  });
88	
89	  it("POST /posts without token should return 401", async () => {
90	    const res = await request(app).post("/posts").send({
91	      title: "Unauthorized Post",
92	      content: "This should fail",
93	    });
94	    expect(res.status).toBe(401);
95	  });
96	
97	  it("POST /posts with valid token should create a post", async () => {
98	    const res = await request(app)
99	      .post("/posts")
100	      .set("Authorization", `Bearer ${token}`)
101	      .send({
102	        title: "Authenticated Post",
103	        content: "This should succeed",
104	      });
105	    expect(res.status).toBe(201);
106	    expect(res.body.title).toBe("Authenticated Post");
107	    // The userId should come from the token, not the request body
108	    expect(res.body).toHaveProperty("userId");
109	    expect(typeof res.body.userId).toBe("number");
110	  });
111	
112	  it("GET /posts should work without auth (public)", async () => {
113	    const res = await request(app).get("/posts");
114	    expect(res.status).toBe(200);
115	    expect(Array.isArray(res.body)).toBe(true);
116	  });
117	
118	  it("GET /posts/:id should work without auth (public)", async () => {
119	    const res = await request(app).get("/posts/1");
120	    expect(res.status).toBe(200);
121	    expect(res.body).toHaveProperty("title");
122	  });
123	
124	  it("PUT /posts/:id without token should return 401", async () => {
125	    const res = await request(app).put("/posts/1").send({
126	      title: "Hacked Title",
127	    });
128	    expect(res.status).toBe(401);
129	  });
130	
131	  it("DELETE /posts/:id without token should return 401", async () => {
132	    const res = await request(app).delete("/posts/1");
133	    expect(res.status).toBe(401);
134	  });
135	});
