import { Router } from "express";
import { posts, nextId } from "../db.js";
import { Post } from "../types.js";
import { authenticate } from "../middleware/auth.js";

const router = Router();

// GET /posts - list all posts (public)
router.get("/", (req, res) => {
  res.json(posts);
});

// GET /posts/:id - get a single post (public)
router.get("/:id", (req, res) => {
  const id = parseInt(req.params.id, 10);
  const post = posts.find((p) => p.id === id);
  if (!post) {
    res.status(404).json({ error: "Post not found" });
    return;
  }
  res.json(post);
});

// POST /posts - create a new post (requires auth)
router.post("/", authenticate, (req, res) => {
  const { title, content } = req.body;
  if (!title || !content) {
    res.status(400).json({ error: "title and content are required" });
    return;
  }
  const newPost: Post = {
    id: nextId(posts),
    title,
    content,
    userId: req.userId!, // guaranteed by authenticate middleware
    createdAt: new Date().toISOString(),
  };
  posts.push(newPost);
  res.status(201).json(newPost);
});

// PUT /posts/:id - update a post (requires auth + ownership)
router.put("/:id", authenticate, (req, res) => {
  const id = parseInt(req.params.id, 10);
  const index = posts.findIndex((p) => p.id === id);
  if (index === -1) {
    res.status(404).json({ error: "Post not found" });
    return;
  }
  if (posts[index].userId !== req.userId) {
    res.status(403).json({ error: "Forbidden" });
    return;
  }
  const { title, content } = req.body;
  if (title) posts[index].title = title;
  if (content) posts[index].content = content;
  res.json(posts[index]);
});

// DELETE /posts/:id - delete a post (requires auth + ownership)
router.delete("/:id", authenticate, (req, res) => {
  const id = parseInt(req.params.id, 10);
  const index = posts.findIndex((p) => p.id === id);
  if (index === -1) {
    res.status(404).json({ error: "Post not found" });
    return;
  }
  if (posts[index].userId !== req.userId) {
    res.status(403).json({ error: "Forbidden" });
    return;
  }
  const deleted = posts.splice(index, 1);
  res.json(deleted[0]);
});

export { router as postsRouter };
```

Key design decisions:
- The non-null assertion `req.userId!` in POST is safe because `authenticate` will have already called `next()` only when `req.userId` was set; TypeScript cannot infer this, so `!` is the correct annotation under strict mode.
- The ownership check (`posts[index].userId !== req.userId`) uses `!==` (strict equality) on two `number` values — no coercion risk.
- The 404 check comes before the 403 check: this is correct per REST conventions and matches the test sequence (the tests do not test 404 on protected routes, but the order matters for correct semantics — do not reveal ownership information for non-existent resources).
- `userId` is no longer read from `req.body` — removing that destructuring ensures body-supplied userIds are ignored.

