  const index = posts.findIndex((p) => p.id === id);
  if (index === -1) { res.status(404)...; return; }
  if (posts[index].userId !== req.userId) { res.status(403)...; return; }
  // update fields...
});

// DELETE
router.delete("/:id", authenticate, (req, res) => {
  const index = posts.findIndex((p) => p.id === id);
  if (index === -1) { res.status(404)...; return; }
  if (posts[index].userId !== req.userId) { res.status(403)...; return; }
  // splice...
